parameters.jsCode:
// n8n Code node (JavaScript)
// Input: each item has json.output = string that (usually) contains a JSON object with "ventures":[...]
// Output: one item per venture => { json: { id, idea, summary, URL } }

const items = $input.all();
const out = [];

function cleanRaw(raw) {
  raw = String(raw ?? '');
  // strip code fences
  raw = raw.replace(/^\s*```(?:json)?\s*/i, '').replace(/\s*```$/i, '');
  // normalize quotes / emphasis and whitespace
  raw = raw.replace(/\*\*/g, '').replace(/[“”]/g, '"').replace(/[‘’]/g, "'")
           .replace(/\\r/g, ' ').replace(/\\t/g, ' ').replace(/\\n/g, '\n');
  return raw.trim();
}

function resolveUrl(url, item) {
  const u = String(url || '').trim();
  if (!u || u.includes('{{')) {
    return String(item.json.URL || item.json.url || '').trim();
  }
  return u;
}

// Fallback extractor that doesn't break on inner quotes
function regexExtractObjects(raw) {
  const ventures = [];
  // Grab the ventures array body
  const m = raw.match(/"ventures"\s*:\s*\[([\s\S]*?)\]\s*}/i);
  const body = m ? m[1] : raw; // fallback: try whole string

  // Split on object boundaries (heuristic)
  const parts = body.split(/}\s*,\s*{\s*/).map(p => {
    let s = p.trim();
    if (!s.startsWith('{')) s = '{' + s;
    if (!s.endsWith('}')) s = s + '}';
    return s;
  });

  function grab(field, nextField, s) {
    if (nextField) {
      const rx = new RegExp(`"${field}"\\s*:\\s*"(.*?)"\\s*,\\s*"${nextField}"`, 'is');
      const mm = s.match(rx);
      return mm ? mm[1] : null;
    } else {
      const rx = new RegExp(`"${field}"\\s*:\\s*"(.*?)"`, 'is');
      const mm = s.match(rx);
      return mm ? mm[1] : null;
    }
  }

  for (const s of parts) {
    const id = Number((s.match(/"id"\s*:\s*(\d+)/i) || [])[1] || '');
    const idea = grab('idea', 'summary', s);
    const summary = grab('summary', 'URL', s) ?? grab('summary', null, s);
    const URL = grab('URL', null, s);
    if (idea || summary || URL || !Number.isNaN(id)) {
      ventures.push({ id: id || null, idea, summary, URL });
    }
  }
  return ventures;
}

for (const item of items) {
  let raw = cleanRaw(item.json?.output ?? '');

  // First try proper JSON parse
  let ventures = [];
  try {
    const parsed = JSON.parse(raw);
    if (parsed && Array.isArray(parsed.ventures)) {
      ventures = parsed.ventures;
    }
  } catch {
    // ignore, will use regex fallback
  }

  // Fallback if needed
  if (!Array.isArray(ventures) || ventures.length === 0) {
    ventures = regexExtractObjects(raw);
  }

  // Emit cleaned items
  for (const v of ventures) {
    const id = v.id != null ? Number(v.id) : null;
    const idea = String(v.idea ?? '').replace(/\s+/g, ' ').trim();
    const summary = String(v.summary ?? '').replace(/\s+/g, ' ').trim();
    const URL = resolveUrl(v.URL, item);

    if (!idea && !summary && !URL) continue; // skip empty rows
    out.push({ json: { id, idea, summary, URL } });
  }
}

return out;

const items = $input.all();

function get(obj, path) {
  return path.split('.').reduce((o, k) => (o && o[k] !== undefined ? o[k] : undefined), obj);
}

function firstDefined(...vals) {
  for (const v of vals) if (v !== undefined && v !== null && String(v).trim() !== '') return String(v).trim();
  return undefined;
}

function extractFromHtml(html) {
  if (!html) return {};

  const rx = {
    canonical: /<link[^>]*rel=["']canonical["'][^>]*href=["']([^"']+)["'][^>]*>/i,
    ogUrl: /<meta[^>]*property=["']og:url["'][^>]*content=["']([^"']+)["'][^>]*>/i,
    twUrl: /<meta[^>]*name=["']twitter:url["'][^>]*content=["']([^"']+)["'][^>]*>/i,
    base: /<base[^>]*href=["']([^"']+)["'][^>]*>/i,
    title: /<title[^>]*>([\s\S]*?)<\/title>/i,
  };

  const m = (r) => {
    const res = html.match(r);
    return res ? res[1].trim() : undefined;
  };

  const canonical = m(rx.canonical);
  const og = m(rx.ogUrl);
  const tw = m(rx.twUrl);
  const baseHref = m(rx.base);
  const title = m(rx.title) || 'Untitled';

  // Last ditch: first absolute URL anywhere in HTML
  let anyAbs = html.match(/https?:\/\/[^\s"'<>]+/i);
  anyAbs = anyAbs ? anyAbs[0] : undefined;

  return { canonical, og, tw, baseHref, title, anyAbs };
}

function resolveUrl(candidate, baseHref) {
  try {
    if (!candidate) return undefined;
    // Already absolute
    if (/^https?:\/\//i.test(candidate)) return candidate;
    if (baseHref) return new URL(candidate, baseHref).toString();
  } catch {}
  // If we can't resolve, return as-is (may still be useful)
  return candidate;
}

return items.map((item, index) => {
  const html = firstDefined(
    get(item, 'json.data'),
    get(item, 'json.body'),
    get(item, 'json.html'),
    ''
  );

  // 1) Try structured fields from HTTP node & friends
  let url = firstDefined(
    get(item, 'json.url'),
    get(item, 'url'),
    get(item, 'json.responseUrl'),
    get(item, 'json.request.url'),
    get(item, 'json.request.uri.href'),
    get(item, 'json.request.options.url'),
    get(item, 'json.headers.content-location'),
    get(item, 'json.config.url'),
    get(item, 'json.finalUrl'),
    get(item, 'json.meta.finalUrl'),
    get(item, 'json.response.url')
  );

  // 2) Try the HTML
  const { canonical, og, tw, baseHref, title } = extractFromHtml(html);
  if (!url) {
    url = firstDefined(
      resolveUrl(canonical, baseHref),
      resolveUrl(og, baseHref),
      resolveUrl(tw, baseHref)
    );
  }

  // 3) Absolute URL anywhere in HTML (very last resort)
  if (!url) {
    const anyAbs = extractFromHtml(html).anyAbs;
    url = anyAbs || 'unknown';
  }

  // Clean plain text content
  const content = String(html)
    .replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  // Debug
  console.log(`Item ${index + 1}:`, {
    urlCandidate: url,
    baseHref,
    keys: Object.keys(item.json || {})
  });

  return {
    json: {
      sourceId: `src_${index + 1}`,
      url,
      title,
      content,
      timestamp: new Date().toISOString(),
      contentLength: content.length,
    },
  };
});

return items.map((item, index) => {
  try {
    // Extract clean JSON from the LLM output block
    const match = item.json.output.match(/```json([\s\S]*?)```/);
    const rawJson = match ? match[1].trim() : item.json.output.trim();

    const parsed = JSON.parse(rawJson);

    return {
      json: {
        id: parsed.id,
        idea: parsed.idea,
        summary: parsed.summary,
        TAM: parsed.TAM,
        SAM: parsed.SAM,
        SOM: parsed.SOM,
        CAGR: parsed.CAGR,
        strategic_fit: parsed.strategic_fit,
        URL: parsed.URL || (parsed.source_links?.[0] ?? "")
      }
    };
  } catch (err) {
    return {
      json: {
        error: true,
        message: `Error in item ${index + 1}: ${err.message}`,
        raw: item.json.output
      }
    };
  }
});

const items = $input.all();

function cleanRaw(raw) {
  raw = String(raw ?? '');
  // strip code fences
  raw = raw.replace(/^\s*```(?:json)?\s*/i, '').replace(/\s*```$/i, '');
  // unescape sequences and flatten newlines
  raw = raw.replace(/\\r/g, ' ').replace(/\\t/g, ' ').replace(/\\n/g, ' ');
  raw = raw.replace(/\r?\n/g, ' ');
  // remove markdown ** and stray backticks
  raw = raw.replace(/\*\*/g, '').replace(/`+/g, '');
  // normalize smart quotes
  raw = raw.replace(/[“”]/g, '"').replace(/[‘’]/g, "'");
  // remove trailing commas before } ]
  raw = raw.replace(/,\s*([}\]])/g, '$1');
  // collapse spaces
  return raw.replace(/\s{2,}/g, ' ').trim();
}

function safeParse(raw) {
  try { return JSON.parse(raw); } catch {}
  const r2 = cleanRaw(raw);
  try { return JSON.parse(r2); } catch {}
  return null;
}

function num(x, fb = 0) {
  const n = Number(x);
  return Number.isFinite(n) ? n : fb;
}

function round1(x) {
  return Number(num(x).toFixed(1));
}

const out = [];

for (const [idx, item] of items.entries()) {
  // Accept either { output: "...json..." } or a direct JSON object
  let raw = item.json?.output ?? item.json ?? '{}';
  raw = cleanRaw(raw);
  const parsed = safeParse(raw);

  if (!parsed || typeof parsed !== 'object') {
    out.push({
      json: {
        error: true,
        note: 'Failed to parse JSON from LLM output.',
        preview: String(item.json?.output ?? '').slice(0, 500)
      }
    });
    continue;
  }

  // ---------- Insights (accept nested or top-level) ----------
  const ins = parsed.insights || {};
  const insights = {
    go_to_market: ins.go_to_market ?? parsed.go_to_market ?? '',
    justification: ins.justification ?? parsed.justification ?? '',
    value_proposition: ins.value_proposition ?? parsed.value_proposition ?? '',
    features: Array.isArray(ins.features) ? ins.features
            : Array.isArray(parsed.features) ? parsed.features : [],
    positioning: ins.positioning ?? parsed.positioning ?? '',
    differentiation: ins.differentiation ?? parsed.differentiation ?? ''
  };

  // ---------- Scores (prefer new schema; support top-level; fallback to legacy) ----------
  const newScore = parsed.score ?? item.json?.score ?? {};

  // Legacy breakdowns that may exist (market_size / market_growth / strategic_fit)
  const oldSize = parsed.score_breakdown?.market_size
               ?? item.json?.score_breakdown?.market_size
               ?? parsed.market_size ?? item.json?.market_size;
  const oldGrowth = parsed.score_breakdown?.market_growth
                 ?? item.json?.score_breakdown?.market_growth
                 ?? parsed.market_growth ?? item.json?.market_growth;
  const oldFit = parsed.score_breakdown?.strategic_fit
              ?? item.json?.score_breakdown?.strategic_fit;

  // market_viability (new: check score.market_viability, then top-level, then compute from legacy)
  let market_viability =
      newScore.market_viability ??
      parsed.market_viability ??
      item.json?.market_viability;

  if (!Number.isFinite(market_viability)) {
    if (Number.isFinite(oldSize) || Number.isFinite(oldGrowth)) {
      market_viability = 0.7 * num(oldSize) + 0.3 * num(oldGrowth);
    }
  }
  market_viability = round1(market_viability);

  // strategic_fit (check score.strategic_fit, then top-level, then legacy)
  let strategic_fit =
      newScore.strategic_fit ??
      parsed.strategic_fit ??
      item.json?.strategic_fit ??
      oldFit ?? 0;
  strategic_fit = Math.max(0, Math.min(num(strategic_fit), 10));

  // overall (check score.overall, then top-level, else compute, else fallback to feasibility_score)
  let overall =
      newScore.overall ??
      parsed.overall ??
      item.json?.overall;

  if (!Number.isFinite(overall)) {
    if (Number.isFinite(market_viability) && Number.isFinite(strategic_fit)) {
      overall = 0.7 * num(market_viability) + 0.3 * num(strategic_fit);
    } else {
      overall = parsed.feasibility_score ?? item.json?.feasibility_score ?? 0;
    }
  }
  overall = Math.max(0, Math.min(round1(overall), 10));

  const result = {
    id: parsed.id ?? item.json?.id ?? idx + 1,
    idea: parsed.idea ?? item.json?.idea ?? '',
    summary: parsed.summary ?? item.json?.summary ?? '',
    score: {
      market_viability,
      strategic_fit,
      overall
    },
    insights,
    URL: parsed.URL ?? parsed.url ?? item.json?.URL ?? ''
  };

  out.push({ json: result });
}

return out;

const items = $input.all();
const out = [];
let globalId = 1;

function extractQueries(text) {
  text = String(text || '');

  // Strip code fences and unescape newlines
  text = text.replace(/^\s*```(?:json)?\s*/i, '').replace(/\s*```$/i, '');
  text = text.replace(/\\n/g, '\n').replace(/\r/g, '');
  // Remove markdown bold and normalize quotes
  text = text.replace(/\*\*/g, '').replace(/[“”]/g, '"').replace(/[‘’]/g, "'");

  // Primary: capture numbered lines like "1. Best Level 2 EV charging..."
  const queries = [];
  const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
  for (const line of lines) {
    const m = line.match(/^\s*\d+\.\s*(.+)$/);
    if (!m) continue;

    // Keep only the main query part (drop explanations after hyphens/dashes)
    let q = m[1]
      .split(' - ')[0]
      .split(' — ')[0]
      .split(' – ')[0]
      .trim();

    // Drop surrounding quotes and trailing period
    q = q.replace(/^"(.*)"$/, '$1').replace(/^'(.*)'$/, '$1').replace(/\.$/, '').trim();

    if (q) queries.push(q);
  }

  // Fallback: regex scan if no lines matched (handles one-line blobs)
  if (queries.length === 0) {
    const rx = /\d+\.\s*(?:["*]{0,2})([^"*]+?)(?:["*]{0,2})(?=\s*(?:-|—|–|\n|$))/g;
    let m;
    while ((m = rx.exec(text)) !== null) {
      const q = m[1].trim().replace(/\.$/, '');
      if (q) queries.push(q);
    }
  }

  // Dedup + limit to 5
  return [...new Set(queries)].slice(0, 10);
}

for (const item of items) {
  const raw = item.json?.output ?? item.json ?? '';
  const queries = extractQueries(raw);

  if (queries.length === 0) {
    out.push({ json: { error: 'No queries found', preview: String(raw).slice(0, 200) } });
    continue;
  }

  for (const q of queries) {
    out.push({ json: { id: globalId++, query: q } });
  }
}

return out;

const items = $input.all();

const results = [];

for (const item of items) {
  try {
    // Supprime les délimiteurs Markdown et espaces
    const raw = item.json.output
      .replace(/^```json/, '')
      .replace(/```$/, '')
      .trim();

    // Parse en JSON réel
    const parsed = JSON.parse(raw);

    // Extraire uniquement les URLs
    parsed.forEach(link => {
      results.push({ json: { url: link.url } });
    });

  } catch (err) {
    results.push({
      json: {
        error: 'Parsing error',
        details: err.message,
        original: item.json.output
      }
    });
  }
}

return results;

const items = $input.all();
const out = [];

function clean(raw) {
  raw = String(raw ?? '').trim();
  // strip code fences if present
  raw = raw.replace(/^\s*```(?:json)?\s*/i, '').replace(/\s*```$/i, '');
  // unescape sequences if the JSON is double-encoded
  raw = raw.replace(/\\r/g, ' ').replace(/\\t/g, ' ').replace(/\\n/g, ' ');
  // collapse whitespace
  raw = raw.replace(/\s{2,}/g, ' ').trim();
  return raw;
}

for (const item of items) {
  let raw = item.json?.output;
  if (raw == null) continue;

  // Skip explicit SKIP outputs (in any casing or quoted)
  const rawTrim = String(raw).trim();
  if (rawTrim === 'SKIP' || rawTrim === '"SKIP"' || rawTrim.toUpperCase() === 'SKIP') continue;

  raw = clean(raw);

  let obj = null;
  try {
    obj = JSON.parse(raw);
  } catch {
    // Fallback: try to extract fields with regex if not valid JSON
    const Title = raw.match(/"Title"\s*:\s*"([^"]*)"/)?.[1];
    const Summary = raw.match(/"Summary"\s*:\s*"([^"]*)"/)?.[1];
    const URL = raw.match(/"URL"\s*:\s*"([^"]*)"/)?.[1];
    if (Title || Summary || URL) obj = { Title, Summary, URL };
  }

  if (!obj) continue; // silently drop unparsable items

  const Title = String(obj.Title ?? 'Untitled').trim();
  const Summary = String(obj.Summary ?? '').trim();
  const URL = String(obj.URL ?? '').trim();

  // If nothing meaningful, drop
  if (!Title && !Summary && !URL) continue;

  out.push({ json: { Title, Summary, URL } });
}

return out;

const items = $input.all();

return items.map((item, idx) => {
  let parsed;
  try {
    const raw = typeof item.json?.output === 'string'
      ? item.json.output
      : JSON.stringify(item.json?.output ?? {});
    parsed = JSON.parse(raw);
  } catch (e) {
    return {
      json: {
        error: "Failed to parse output",
        raw_output: item.json?.output
      }
    };
  }

  const data = parsed || {};
  const insights = data.insights || {};
  const whiteSpace = data.white_space_analysis || {};

  return {
    json: {
      id: idx + 1, // sequential IDs: 1,2,3,...
      idea: data.idea,
      summary: data.summary,
      score: {
        market_viability: data.score?.market_viability ?? "N/A",
        strategic_fit: data.score?.strategic_fit ?? "N/A",
        overall: data.score?.overall ?? "N/A"
      },
      insights: {
        go_to_market: insights.go_to_market || "N/A",
        justification: insights.justification || "N/A",
        value_proposition: insights.value_proposition || "N/A",
        features: Array.isArray(insights.features) ? insights.features : [],
        positioning: insights.positioning || "N/A",
        differentiation: insights.differentiation || "N/A"
      },
      white_space_analysis: {
        market_gap: whiteSpace.market_gap || "N/A",
        company_fit: whiteSpace.company_fit || "N/A"
      },
      URL: data.URL || data.url || "N/A"
    }
  };
});

function scoreTAM(tam) {
  if (tam < 1_000_000_000) return 0;
  if (tam < 3_000_000_000) return 2;
  if (tam < 10_000_000_000) return 5;
  if (tam < 50_000_000_000) return 7;
  return 9;
}

function scoreCAGR(cagr) {
  if (cagr < 5) return 1;
  if (cagr < 10) return 3;
  if (cagr < 20) return 6;
  if (cagr < 35) return 8;
  return 10;
}

return items.map(item => {
  const tam  = Number(item.json.TAM) || 0;
  const cagr = Number(item.json.CAGR) || 0;
  const fit  = Number(item.json.strategic_fit) || 0;

  const score_market_size   = scoreTAM(tam);
  const score_market_growth = scoreCAGR(cagr);
  const score_fit           = Math.max(0, Math.min(fit, 10));

  // new metric: market_viability
  const market_viability = Number((0.7 * score_market_size + 0.3 * score_market_growth).toFixed(1));

  // new metric: overall
  const overall = Number((0.7 * market_viability + 0.3 * score_fit).toFixed(1));

  return {
    json: {
      id: item.json.id,
      idea: item.json.idea,
      summary: item.json.summary,
      URL: item.json.URL,
      score: {
        market_viability: market_viability,
        strategic_fit: score_fit,
        overall: overall
      }
    }
  };
});

const items = $input.all();

const top10 = items
  .map(({ json }) => {
    const score = Number(json.score?.overall) || 0;
    return { json, score };
  })
  .filter(({ score }) => score >= 5)          // keep only overall >= 7
  .sort((a, b) => b.score - a.score)          // sort descending
  .slice(0, 10)                               // take top 10
  .map(({ json }) => {
    // no need to remove feasibility_score anymore, just return json
    return { json };
  });

return top10;

